appsmith.onReady(() => {
  generateExecutiveSummary();
});
appsmith.onModelChange(() => {
  generateExecutiveSummary();
});
function generateExecutiveSummary() {
  const data = appsmith.model;
  const current = data.current || {};

  // --- 1. AGGREGATE CURRENT RISKS (Baseline) ---

  // Web/Cookie Risks
  const cookies = current.cookies || [];
  const highEgressCookies = cookies.filter(c => c.thirdParty === true).length;
  const jsExposureCookies = cookies.filter(c => !c.httpOnly).length;
  const totalWebSignals = highEgressCookies + jsExposureCookies;

  // Inferred Model Risks
  const scripts = current.scripts || {};
  const rootKey = Object.keys(scripts)[0];
  const scriptMap = rootKey ? scripts[rootKey] : {};
  let sensitivePiiCount = 0;
  let piiCount = 0;
  Object.values(scriptMap).forEach(info => {
    if ((info["sensitive PIIs"] || []).length > 0) sensitivePiiCount++;else if ((info.PIIs || []).length > 0) piiCount++;
  });
  const totalModelSignals = sensitivePiiCount + piiCount;

  // Network/Shadow AI Risks
  const logs = current.logs || [];
  const unsanctionedAI = ["api.openai.com", "claude.ai", "mistral.ai", "perplexity.ai"];
  let shadowCount = 0;
  logs.forEach(e => {
    if (e.method === "Network.requestWillBeSent") {
      const url = e.params.request.url || "";
      if (unsanctionedAI.some(ai => url.includes(ai))) shadowCount++;
    }
  });

  // Policy Drift Proxy
  const hasDrift = shadowCount > 0 || sensitivePiiCount > 0;

  // --- 2. UPDATE BASELINE UI ---
  document.getElementById('web-egress-count').textContent = totalWebSignals;
  document.getElementById('model-risk-count').textContent = totalModelSignals;
  document.getElementById('shadow-ai-count').textContent = shadowCount;
  const driftEl = document.getElementById('policy-drift-status');
  driftEl.textContent = hasDrift ? "Detected" : "Aligned";
  driftEl.style.color = hasDrift ? "#e74c3c" : "#2ecc71";
  driftEl.parentElement.style.borderTopColor = hasDrift ? "#e74c3c" : "#2ecc71";

  // --- 3. OVERALL THREAT LEVEL ---
  const totalSignals = totalWebSignals + totalModelSignals + shadowCount;
  document.getElementById('total-signals').textContent = totalSignals;
  const threatEl = document.getElementById('overall-threat-level');
  const contextEl = document.getElementById('threat-context');
  const heroCard = threatEl.parentElement;
  if (sensitivePiiCount > 0 || shadowCount > 0) {
    threatEl.textContent = "CRITICAL";
    threatEl.className = "value text-critical";
    heroCard.style.borderLeftColor = "#e74c3c";
    contextEl.textContent = "Active Shadow AI or Sensitive PII Leakage";
  } else if (totalSignals > 5) {
    threatEl.textContent = "HIGH";
    threatEl.className = "value text-warning";
    heroCard.style.borderLeftColor = "#f39c12";
    contextEl.textContent = "Multiple Exposure Signals Detected";
  } else {
    threatEl.textContent = "NOMINAL";
    threatEl.className = "value text-safe";
    heroCard.style.borderLeftColor = "#2ecc71";
    contextEl.textContent = "No critical exposure signals";
  }

  // --- 4. TOP 3 PRIORITY FINDINGS LOGIC ---
  const findingsList = [];
  if (shadowCount > 0) findingsList.push({
    text: `<b>Critical:</b> Detected ${shadowCount} unsanctioned Shadow AI network requests.`,
    severity: 3
  });
  if (sensitivePiiCount > 0) findingsList.push({
    text: `<b>Critical:</b> Found ${sensitivePiiCount} instances of sensitive PII exposure in client-side scripts.`,
    severity: 3
  });
  if (highEgressCookies > 0) findingsList.push({
    text: `<b>High:</b> Active third-party data egress signals detected on ${highEgressCookies} cookies.`,
    severity: 2
  });
  if (hasDrift) findingsList.push({
    text: `<b>High:</b> Policy Drift detected: Observed AI data flows diverge from stated data usage disclosures.`,
    severity: 2
  });
  if (jsExposureCookies > 0) findingsList.push({
    text: `<b>Medium:</b> Found ${jsExposureCookies} cookies lacking HttpOnly protection (JS-Visible).`,
    severity: 1
  });
  findingsList.sort((a, b) => b.severity - a.severity);
  const top3 = findingsList.slice(0, 3);
  const topFindingsUl = document.getElementById('top-findings-list');
  if (topFindingsUl) {
    topFindingsUl.innerHTML = "";
    if (top3.length === 0) {
      topFindingsUl.innerHTML = "<li>No critical or high-priority findings detected in the current baseline.</li>";
    } else {
      top3.forEach(f => {
        const li = document.createElement('li');
        li.innerHTML = f.text;
        li.style.marginBottom = "8px";
        topFindingsUl.appendChild(li);
      });
    }
  }

  // --- 5. EVOLUTION / DELTA LOGIC ---
  const prevWebSignals = getMockOrRealPrevValue(totalWebSignals, 1);
  const prevShadowCount = getMockOrRealPrevValue(shadowCount, 2);
  const prevModelSignals = getMockOrRealPrevValue(totalModelSignals, 1);
  const netChange = totalSignals - (prevWebSignals + prevShadowCount + prevModelSignals);
  const trendEl = document.getElementById('trend-verdict');
  const trendCard = trendEl.parentElement;
  if (netChange > 0) {
    trendEl.textContent = "Degraded";
    trendEl.style.color = "#e74c3c";
    trendCard.style.borderLeftColor = "#e74c3c";
  } else if (netChange < 0) {
    trendEl.textContent = "Improved";
    trendEl.style.color = "#2ecc71";
    trendCard.style.borderLeftColor = "#2ecc71";
  } else {
    trendEl.textContent = "Stable";
    trendEl.style.color = "#3498db";
    trendCard.style.borderLeftColor = "#3498db";
  }

  // --- 6. RENDER DELTA TABLE ---
  const tbody = document.getElementById('delta-table-body');
  if (tbody) {
    tbody.innerHTML = "";
    const rows = [createDeltaRow("Web Egress Signals", prevWebSignals, totalWebSignals, true), createDeltaRow("Shadow AI Traffic", prevShadowCount, shadowCount, true), createDeltaRow("Inferred Model Risks", prevModelSignals, totalModelSignals, true)];
    rows.forEach(r => tbody.appendChild(r));
  }
}
function getMockOrRealPrevValue(currentValue, mockDiff) {
  return Math.max(0, currentValue - mockDiff);
}
function createDeltaRow(category, prev, curr, lowerIsBetter) {
  const diff = curr - prev;
  const tr = document.createElement('tr');
  let verdict = "Stable";
  let badgeClass = "badge-neutral";
  if (diff !== 0) {
    const isBad = lowerIsBetter ? diff > 0 : diff < 0;
    verdict = isBad ? "Risk Increased" : "Risk Reduced";
    badgeClass = isBad ? "badge-critical" : "badge-safe";
  } else {
    verdict = "No Change";
  }
  tr.innerHTML = `
        <td><strong>${category}</strong></td>
        <td>${prev}</td>
        <td>${curr}</td>
        <td>${diff > 0 ? '+' : ''}${diff}</td>
        <td><span class="badge ${badgeClass}">${verdict}</span></td>
    `;
  return tr;
}

